        // ── Voice TTS Guide ──
        "guide_nav_usecase_voice": "Voice TTS",
        "guide_voice_title": "🔊 Voice Chat — Bot TTS Real-Time Voice Reply",
        "guide_voice_subtitle": "Let your AI agent \"speak out loud\" — voice replies straight from the phone speaker",
        "guide_voice_what": "What is this?",
        "guide_voice_what_desc": "EClawbot's <strong>TTS (Text-to-Speech) API</strong> lets Bots broadcast voice messages in real time through the Android device speaker. Voice plays even when the App is in the background. Ideal for scenarios requiring voice interaction — customer service voice replies, voice assistants, accessibility aids, and more.",
        "guide_voice_how": "How It Works",
        "guide_voice_how_desc": "Bot calls TTS API → Server forwards to App → Android TextToSpeech engine reads aloud → User hears the voice reply",
        "guide_voice_api": "API Usage",
        "guide_voice_api_desc": "A Bot sends <code>POST /api/device/tts</code> to make the phone read text aloud:",
        "guide_voice_params": "Parameters",
        "guide_voice_param": "Parameter",
        "guide_voice_required": "Required",
        "guide_voice_desc": "Description",
        "guide_voice_param_text": "Text to read aloud (max 500 characters)",
        "guide_voice_param_lang": "BCP-47 language code, default zh-TW (supports en-US, ja-JP, ko-KR, etc.)",
        "guide_voice_param_speed": "Speed 0.5–2.0, default 1.0",
        "guide_voice_param_pitch": "Pitch 0.5–2.0, default 1.0",
        "guide_voice_scenarios": "Use Cases",
        "guide_voice_scene1_title": "🎧 Customer Service Voice Reply",
        "guide_voice_scene1_desc": "An e-commerce support Bot replies with text and simultaneously broadcasts key information via TTS. \"Your order has shipped and is expected to arrive tomorrow.\" Users can receive info without staring at the screen.",
        "guide_voice_scene2_title": "🗣️ Voice Assistant Mode",
        "guide_voice_scene2_desc": "Combine with voice input for a full voice conversation experience. User speaks → Bot understands → TTS voice reply, just like Siri / Google Assistant.",
        "guide_voice_scene3_title": "♿ Accessibility Aid",
        "guide_voice_scene3_desc": "Visually impaired users can receive all Bot replies via voice. Multi-language support and adjustable speed ensure accessible information delivery.",
        "guide_voice_scene4_title": "🌍 Multi-Language Broadcast",
        "guide_voice_scene4_desc": "Supports Traditional Chinese / English / Japanese / Korean / Thai and more. Ideal for multilingual customer service — the Bot auto-detects language and replies in the matching voice.",
        "guide_voice_flow": "Full Flow",
        "guide_voice_example": "Code Example",
        "guide_voice_example_desc": "An OpenClaw Bot triggers voice while replying to a user:",
        "guide_voice_features": "Technical Highlights",
        "guide_voice_feat1": "📱 <strong>Background Playback</strong>: Voice plays even when the App is in the background or screen is locked (Foreground Service)",
        "guide_voice_feat2": "🔔 <strong>FCM Fallback</strong>: Falls back to Firebase Cloud Messaging when Socket.IO disconnects",
        "guide_voice_feat3": "🌐 <strong>Multi-Language</strong>: Supports all languages available on the Android TextToSpeech engine",
        "guide_voice_feat4": "⚡ <strong>Low Latency</strong>: Typically less than 1 second from Bot call to user hearing the voice",
        "guide_voice_feat5": "🎛️ <strong>Adjustable Parameters</strong>: Speed and pitch are fully customizable (0.5x–2.0x)",
        "guide_voice_note": "💡 <strong>Note:</strong> TTS currently supports Android devices only. iOS support is planned. Text limit is 500 characters; for longer text, split into multiple calls.",
        "guide_voice_cta_title": "Try It Now",
        "guide_voice_cta_api": "API Docs: <a href=\"https://eclawbot.com/api/skill-doc\" target=\"_blank\" rel=\"noopener\">Full API Skill Doc</a>",
        "guide_voice_cta_app": "Android App: <a href=\"https://play.google.com/store/apps/details?id=com.hank.clawlive\" target=\"_blank\" rel=\"noopener\">Download on Google Play</a>",

