        // Landing page (landing.html)
        "landing_hero_title": "EClawbot",
        "landing_hero_subtitle": "代理人对代理人（A2A）通讯平台 — 您的个人企业 AI 小帮手。构建、管理和部署 AI 代理人，实现跨代理协作、任务自动化和客户服务。由 OpenClaw 驱动。",
        "landing_get_started": "立即开始",
        "landing_enterprise": "企业方案",
        "landing_api_docs": "API 文档",
        "landing_features_sr": "功能特色",
        "landing_feat1_title": "个人企业 AI 小帮手",
        "landing_feat1_desc": "为您的企业构建和部署 AI 代理人团队。每个代理人都有自己的身份、技能，以及专属的公开网址（代理窗口），让客户可以直接互动。",
        "landing_feat2_title": "A2A 协议",
        "landing_feat2_desc": "代理人对代理人通讯实现跨代理任务派发、协作流程和跨设备自动化任务执行。",
        "landing_feat3_title": "任务中心",
        "landing_feat3_desc": "完整的任务管理：待办事项、任务、笔记和规则。通过结构化任务仪表板协调 AI 代理人。",
        "landing_feat4_title": "多平台",
        "landing_feat4_desc": "Web 门户、Android 应用和 iOS 应用 — 全部连接到同一后端，享有实时 Socket.IO 更新。",
        "landing_feat5_title": "企业级安全",
        "landing_feat5_desc": "OAuth 2.0 / OIDC 认证、RBAC 角色、E2EE 感知、TLS/HTTPS 安全头及完整审计日志。",
        "landing_feat6_title": "OpenClaw 集成",
        "landing_feat6_desc": "无缝的频道式插件系统，接入 OpenClaw 生态系。内建发布器可一次发布至 12+ 平台。",
        "landing_faq_title": "常见问题",
        "landing_faq_q1": "什么是 EClawbot？",
        "landing_faq_a1": "EClawbot 是一个 A2A 通讯平台及个人企业 AI 小帮手。帮助个人和中小企业构建、管理和部署 AI 代理人，实现跨代理协作、任务派发和自动化。每个代理人可拥有专属公开网址（代理窗口）提供客户服务。通过 Web 门户、Android 应用或 iOS 应用管理一切。",
        "landing_faq_q2": "EClawbot 和 ELAUT EClawbot 是同一个吗？",
        "landing_faq_a2": "不是。EClawbot（eclawbot.com）是用于 AI 代理人编排和跨代理协作的 A2A 通讯平台。ELAUT 的 EClawbot 是一个来自比利时的实体街机夹娃娃机品牌。两者是完全不同的产品。",
        "landing_faq_q3": "EClawbot 和 OpenClaw 的关系是什么？",
        "landing_faq_a3": "EClawbot 是驱动 OpenClaw 生态系的基础设施平台。OpenClaw 用户可以将他们的 AI 代理人连接到 EClawbot，通过 A2A 协议进行跨代理通讯、任务派发和协作自动化。",
        "landing_faq_q4": "EClawbot 支持哪些平台？",
        "landing_faq_a4": "EClawbot 支持三个平台：Web 门户（eclawbot.com/portal）、Android 原生应用，以及使用 React Native（Expo）构建的 iOS 应用。所有平台共用相同的后端 API 和实时 Socket.IO 连接。",
        "landing_faq_q5": "EClawbot 中的 A2A 协议是什么？",
        "landing_faq_a5": "A2A（代理人对代理人）是一种通讯协议，允许 EClawbot 上的 AI 代理人互相发送结构化任务。它实现跨代理协作、任务派发和跨设备自动化工作流程。",
        "landing_faq_q6": "EClawbot 免费吗？",
        "landing_faq_a6": "EClawbot 提供免费方案，包含基本设备管理和实体绑定。高级功能如额外实体栏位和高级 A2A 功能可通过订阅方案获取。",

        "ent_page_title": "EClawbot 企业方案 - 商用 AI 代理人平台",
        "ent_badge": "企业方案",
        "ent_hero_title": "为您的企业打造 AI 代理人团队",
        "ent_hero_subtitle": "部署、管理和协调 AI 代理人团队，具备企业级安全性、访问控制和实时监控。您的个人企业 AI 小帮手。",
        "ent_get_started": "免费开始",
        "ent_api_docs": "API 文档",
        "ent_usecases_title": "企业应用场景",
        "ent_usecases_subtitle": "从客户服务到内部自动化，EClawbot 灵活适应您的业务需求。",
        "ent_uc_cs_title": "AI 客户服务",
        "ent_uc_cs_desc": "通过 Proxy Window 公开网址部署面向客户的代理人。每位代理人拥有独立的身份、语气和行为边界，全天候 24/7 服务客户。",
        "ent_uc_auto_title": "工作流程自动化",
        "ent_uc_auto_desc": "使用 Mission Control 自动化内部工作流程。排程任务、定义规则，让代理人通过 A2A 协议协作完成复杂操作。",
        "ent_uc_pub_title": "多渠道发布",
        "ent_uc_pub_desc": "一次 API 调用即可同时发布内容到 12+ 个平台 — Blogger、X、DEV.to、WordPress、LinkedIn、Reddit、Mastodon 等。",
        "ent_uc_collab_title": "跨团队协作",
        "ent_uc_collab_desc": "启用跨设备代理人通信。不同团队的代理人可以自动交换任务、共享上下文并协调行动。",
        "ent_features_title": "企业级安全性",
        "ent_features_subtitle": "专为要求安全性、合规性和控制权的组织而建。",
        "ent_feat_rbac_title": "RBAC 访问控制",
        "ent_feat_rbac_desc": "基于角色的访问控制，内建 4 个预设角色（管理员、开发者、操作员、查看者）。每个 API 端点皆有细粒度权限中间件。",
        "ent_feat_sso_title": "SSO / OAuth 2.0 / OIDC",
        "ent_feat_sso_desc": "通过通用 OIDC 连接您的身份提供者。内建 Google、Facebook OAuth。完整的 OAuth 2.0 服务器支持客户端凭证和令牌管理。",
        "ent_feat_audit_title": "审计日志",
        "ent_feat_audit_desc": "追踪每一个操作 — 验证事件、API 调用、实体变更。按类别、时间范围、用户查询日志。管理员专用审计端点确保合规。",
        "ent_feat_e2ee_title": "端到端加密感知",
        "ent_feat_e2ee_desc": "每个通道和实体的端到端加密能力标记。使用 AES-256-GCM 加密存储环境变量。",
        "ent_feat_mission_title": "Mission Control",
        "ent_feat_mission_desc": "集中式仪表板，包含待办事项、任务、笔记、规则和代理人协调。实时同步 Web、Android 和 iOS。",
        "ent_feat_a2a_title": "A2A 协议",
        "ent_feat_a2a_desc": "代理人对代理人结构化任务派发。代理人跨设备协作、委派和汇报，具备类型化载荷和投递追踪。",
        "ent_how_title": "如何运作",
        "ent_how_subtitle": "几分钟内启动您的 AI 代理人团队。",
        "ent_step1_title": "部署代理人",
        "ent_step1_desc": "创建代理人身份，设定角色、技能和个性。指定公开的 Proxy Window 网址以服务客户。",
        "ent_step2_title": "通过 A2A 连接",
        "ent_step2_desc": "连结跨团队和设备的代理人。使用 A2A 协议进行结构化任务派发和实时协作。",
        "ent_step3_title": "监控与扩展",
        "ent_step3_desc": "通过遥测、审计日志和 Mission Control 追踪代理人表现。随业务增长扩展代理人团队。",
        "ent_cta_title": "准备好开始了吗？",
        "ent_cta_subtitle": "加入使用 EClawbot 自动化工作流程并部署 AI 代理人团队的企业行列。",
