        "guide_crossdevice_web_li4": "填写违禁词、黑名单/白名单、频率限制等",
        "guide_crossdevice_web_li5": "点击 <strong>Save</strong> 保存设置",
        "guide_crossdevice_preview_preinject": "Pre-inject",
        "guide_crossdevice_preview_preinject_val": "你是一名店铺助理，请用中文回复",
        "guide_crossdevice_preview_forbidden": "违禁词",
        "guide_crossdevice_preview_ratelimit": "频率限制",
        "guide_crossdevice_preview_media": "媒体",
