        // ── Voice TTS Guide ──
        "guide_nav_usecase_voice": "音声会話 TTS",
        "guide_voice_title": "🔊 音声会話 — Bot TTS リアルタイム音声返信",
        "guide_voice_subtitle": "AI エージェントに「声を出して話させる」— スマホのスピーカーからユーザーに直接音声で返信",
        "guide_voice_what": "これは何ですか？",
        "guide_voice_what_desc": "EClawbot の <strong>TTS（Text-to-Speech）API</strong> により、Bot は Android デバイスのスピーカーを通じてリアルタイムに音声を再生できます。App がバックグラウンドでも音声は正常に再生されます。カスタマーサービスの音声返信、音声アシスタント、アクセシビリティ支援など、音声インタラクションが必要なシーンに最適です。",
        "guide_voice_how": "仕組み",
        "guide_voice_how_desc": "Bot が TTS API を呼び出す → サーバーが App に転送 → Android TextToSpeech エンジンが読み上げ → ユーザーが音声返信を聞く",
        "guide_voice_api": "API の使い方",
        "guide_voice_api_desc": "Bot が <code>POST /api/device/tts</code> を送信するとスマホがテキストを読み上げます：",
        "guide_voice_params": "パラメータ説明",
        "guide_voice_param": "パラメータ",
        "guide_voice_required": "必須",
        "guide_voice_desc": "説明",
        "guide_voice_param_text": "読み上げるテキスト（最大500文字）",
        "guide_voice_param_lang": "BCP-47 言語コード、デフォルト zh-TW（en-US, ja-JP, ko-KR などに対応）",
        "guide_voice_param_speed": "速度 0.5～2.0、デフォルト 1.0",
        "guide_voice_param_pitch": "ピッチ 0.5～2.0、デフォルト 1.0",
        "guide_voice_scenarios": "利用シーン",
        "guide_voice_scene1_title": "🎧 カスタマーサービス音声返信",
        "guide_voice_scene1_desc": "EC カスタマーサポート Bot がテキスト返信と同時に TTS で重要情報を音声再生。「ご注文は発送済みです。明日到着予定です。」画面を見なくても情報を受け取れます。",
        "guide_voice_scene2_title": "🗣️ 音声アシスタントモード",
        "guide_voice_scene2_desc": "音声入力と組み合わせて完全な音声会話体験を実現。ユーザーが話す → Bot が理解 → TTS 音声返信、Siri / Google Assistant のように。",
        "guide_voice_scene3_title": "♿ アクセシビリティ支援",
        "guide_voice_scene3_desc": "視覚障害のあるユーザーが Bot の全返信を音声で受け取れます。多言語対応・速度調整可能で、情報のバリアフリーを実現します。",
        "guide_voice_scene4_title": "🌍 多言語再生",
        "guide_voice_scene4_desc": "繁体中国語 / 英語 / 日本語 / 韓国語 / タイ語など多数の言語に対応。多言語カスタマーサービスに最適 — Bot が言語を自動検出し、対応する音声で返信します。",
        "guide_voice_flow": "完全なフロー",
        "guide_voice_example": "コード例",
        "guide_voice_example_desc": "OpenClaw Bot がユーザーに返信する際に同時に音声をトリガー：",
        "guide_voice_features": "技術的特徴",
        "guide_voice_feat1": "📱 <strong>バックグラウンド再生</strong>：App がバックグラウンドやロック画面でも音声再生可能（Foreground Service）",
        "guide_voice_feat2": "🔔 <strong>FCM フォールバック</strong>：Socket.IO 切断時は Firebase Cloud Messaging 経由でトリガー",
        "guide_voice_feat3": "🌐 <strong>多言語対応</strong>：Android TextToSpeech エンジンが対応する全言語をサポート",
        "guide_voice_feat4": "⚡ <strong>低遅延</strong>：Bot の呼び出しからユーザーが聞くまで通常 1 秒未満",
        "guide_voice_feat5": "🎛️ <strong>調整可能なパラメータ</strong>：速度・ピッチともにカスタマイズ可能（0.5x～2.0x）",
        "guide_voice_note": "💡 <strong>ヒント：</strong>TTS は現在 Android デバイスのみ対応しています。iOS 対応は計画中です。テキスト上限は 500 文字で、超える場合は分割して呼び出してください。",
        "guide_voice_cta_title": "今すぐ試す",
