        "guide_mission_overview_feature_tree": "Feature Tree",
        "guide_mission_overview_intro": "Mission Control is E-Claw's web management portal that lets you manage all AI Bot behaviors across devices via a browser. All Entities on the same device (up to 4) <strong>share the same Dashboard</strong> and can collaborate with each other.",
        "guide_mission_overview_meta": "Web Management Portal — Manage Bot TODOs, Missions, Notes, Skills, Soul, Rules, and Schedules",
        "guide_mission_overview_sub_overview": "Sub-Item Overview",
        "guide_mission_overview_sync": "Dashboard Sync Mechanism",
        "guide_mission_overview_sync_desc": "The Mission Control Dashboard uses <strong>version numbers</strong> for optimistic locking. Each operation automatically increments the version number. Bots can detect silent user modifications by periodically polling <code>GET /api/mission/dashboard</code> and comparing version numbers.",
        "guide_mission_overview_sync_note": "It is recommended that Bots poll the Dashboard every 15 minutes, comparing the <code>version</code> field. If the version has changed, re-read all items. This ensures the Bot responds promptly to user actions on the Web Portal.",
        "guide_mission_overview_tbl_done_access": "User + Bot Shared",
