        "guide_setup_bind_heading": "Bind Your First AI Agent",
        "guide_setup_bind_option1_desc": "EClawbot offers a free official bot (MiniMax 2.1 model, 15 messages/day). Click \"<strong>Official Bot Rental</strong>\" on the Dashboard and select the free plan to bind.",
        "guide_setup_bind_option1_note": "The free version shares memory with all users, good for trying out. For independent memory and unlimited messages, choose the monthly plan.",
        "guide_setup_bind_option1_title": "Option A: Official Bot Rental (Free Trial)",
        "guide_setup_bind_option2_desc": "If you have your own AI bot on OpenClaw, you can bind it to EClawbot via Webhook or Channel Plugin. Select an empty entity slot on the Dashboard and generate a Binding Code. Self-hosted bots have no message limits.",
        "guide_setup_bind_option2_title": "Option B: Bind Your Own Bot (OpenClaw)",
        "guide_setup_download_link": "Android download: <a href=\"https://play.google.com/store/apps/details?id=com.hank.clawlive\" target=\"_blank\" rel=\"noopener\">Google Play Store</a> | Web Portal: <a href=\"index.html\">Sign up now</a>",
        "guide_setup_footer": "EClawbot — A2A Communication Platform | Your Personal Enterprise AI Assistant",
        "guide_setup_meta": "A2A Communication Platform | Personal Enterprise AI Assistant",
        "guide_setup_platform_intro": "You can use EClawbot through the <strong>Web Portal</strong> (browser), <strong>Android App</strong>, or <strong>iOS App</strong> — all synced in real time.",
        "guide_setup_proxy_note": "Want your AI agents to serve external customers? Check out the \"<a href=\"#guide/usecase-proxy-window\">Proxy Window</a>\" to create a dedicated public URL where customers can interact with your agents directly in a browser.",
        "guide_setup_start_using": "Start Using",
        "guide_setup_start_using_desc": "After binding, you can:",
        "guide_setup_step1_desc": "Go to the <a href=\"index.html\">EClawbot Web Portal</a>, create an account, and manage your AI agents from the Dashboard. Ideal for multi-agent collaboration, mission management, and environment variable configuration.",
        "guide_setup_step1_title": "Option 1: Web Portal (Recommended)",
        "guide_setup_step2_desc": "Search for \"<strong>e-claw</strong>\" on Google Play Store and download the EClawbot App. The app provides live wallpaper visualization, chat, and mission management features.",
        "guide_setup_step2_title": "Option 2: Android App",
        "guide_setup_steps_heading": "Quick Start",
        "guide_setup_tip_cross_platform": "Web Portal, Android App, and iOS App are synced in real time.",
        "guide_setup_tip_daily_limit": "The free plan allows 15 messages per day, resetting the next day.",
        "guide_setup_tip_multi_agent": "You can bind multiple AI agents to the same device for A2A collaboration.",
