        "guide_crossdevice_h3_api": "Phương pháp API",
        "guide_crossdevice_api_auth": "Xác thực: Header <code>x-device-secret</code>",
        "guide_crossdevice_h2_usecases": "Trường hợp sử dụng",
        "guide_crossdevice_uc1_title": "🛡️ Chống quấy rối",
        "guide_crossdevice_uc1_desc": "Đặt từ cấm để lọc nội dung không phù hợp, bật giới hạn tốc độ để ngăn gửi tin nhắn liên tục, và đưa người dùng xấu vào danh sách đen vĩnh viễn.",
        "guide_crossdevice_uc2_title": "🔒 Dịch vụ chỉ dành cho VIP",
        "guide_crossdevice_uc2_desc": "Bật chế độ danh sách trắng để chỉ cho phép Public Code của khách hàng cụ thể truy cập agent của bạn, tạo kênh VIP độc quyền.",
        "guide_crossdevice_uc3_title": "📝 Đặt ngữ cảnh trước",
        "guide_crossdevice_uc3_desc": "Sử dụng Pre-inject để tự động thêm lời nhắc vai trò trước mỗi tin nhắn bên ngoài, ví dụ: 'Bạn là cố vấn du lịch, hãy trả lời với giọng điệu thân thiện.'",
        "guide_crossdevice_h2_tips": "Thực hành tốt nhất",
        "guide_crossdevice_tip_li1": "✅ <strong>Bắt đầu lỏng lẻo, siết chặt sau</strong>: Bắt đầu với cài đặt mặc định và dần dần thêm hạn chế khi cần",
        "guide_crossdevice_tip_li2": "✅ <strong>Sử dụng Pre-inject thông minh</strong>: Cung cấp cho Bot ngữ cảnh vai trò đầy đủ với mỗi tin nhắn đến",
        "guide_crossdevice_tip_li3": "✅ <strong>Đặt tin nhắn từ chối</strong>: Thân thiện hơn từ chối im lặng — cho người dùng bị chặn biết lý do",
        "guide_crossdevice_tip_li4": "✅ <strong>Kết hợp với Card Holder</strong>: Chặn ai đó trong Card Holder hoạt động như kiểm tra cổng đầu tiên",
        "guide_crossdevice_warn": "⚠️ Giới hạn tốc độ được tính trong bộ nhớ và đặt lại khi khởi động lại máy chủ. Danh sách đen, danh sách trắng và từ cấm được lưu trữ vĩnh viễn trong cơ sở dữ liệu.",
        "guide_crossdevice_note_back": "← <a href=\"#guide/usecase-proxy-window\">Quay lại hướng dẫn cửa sổ proxy</a>",
        "guide_crossdevice_config_title": "Cross-Device Msg",

        // ── Voice TTS Guide ──
        "guide_nav_usecase_voice": "Hội thoại giọng nói TTS",
        "guide_voice_title": "🔊 Hội thoại giọng nói — Bot TTS phản hồi giọng nói thời gian thực",
        "guide_voice_subtitle": "Cho AI agent của bạn \"nói thành tiếng\" — phản hồi giọng nói trực tiếp qua loa điện thoại",
        "guide_voice_what": "Đây là gì?",
        "guide_voice_what_desc": "<strong>TTS (Text-to-Speech) API</strong> của EClawbot cho phép Bot phát giọng nói thời gian thực qua loa thiết bị Android. Giọng nói vẫn phát bình thường ngay cả khi ứng dụng chạy nền. Phù hợp cho các tình huống cần tương tác giọng nói — phản hồi giọng nói dịch vụ khách hàng, trợ lý giọng nói, hỗ trợ tiếp cận, v.v.",
        "guide_voice_how": "Nguyên lý hoạt động",
        "guide_voice_how_desc": "Bot gọi TTS API → Máy chủ chuyển tiếp đến App → Engine Android TextToSpeech đọc to → Người dùng nghe phản hồi giọng nói",
        "guide_voice_api": "Cách sử dụng API",
        "guide_voice_api_desc": "Bot gửi <code>POST /api/device/tts</code> để điện thoại đọc to văn bản:",
        "guide_voice_params": "Mô tả tham số",
        "guide_voice_param": "Tham số",
        "guide_voice_required": "Bắt buộc",
        "guide_voice_desc": "Mô tả",
        "guide_voice_param_text": "Văn bản cần đọc to (tối đa 500 ký tự)",
        "guide_voice_param_lang": "Mã ngôn ngữ BCP-47, mặc định zh-TW (hỗ trợ en-US, ja-JP, ko-KR, v.v.)",
        "guide_voice_param_speed": "Tốc độ 0.5–2.0, mặc định 1.0",
        "guide_voice_param_pitch": "Cao độ 0.5–2.0, mặc định 1.0",
        "guide_voice_scenarios": "Tình huống sử dụng",
        "guide_voice_scene1_title": "🎧 Phản hồi giọng nói dịch vụ khách hàng",
        "guide_voice_scene1_desc": "Bot dịch vụ khách hàng thương mại điện tử vừa trả lời văn bản vừa phát thông tin quan trọng qua TTS. \"Đơn hàng của bạn đã được gửi, dự kiến đến vào ngày mai.\" Người dùng không cần nhìn màn hình vẫn nhận được thông tin.",
        "guide_voice_scene2_title": "🗣️ Chế độ trợ lý giọng nói",
        "guide_voice_scene2_desc": "Kết hợp với nhập liệu giọng nói để tạo trải nghiệm hội thoại giọng nói hoàn chỉnh. Người dùng nói → Bot hiểu → TTS phản hồi giọng nói, giống như Siri / Google Assistant.",
        "guide_voice_scene3_title": "♿ Hỗ trợ tiếp cận",
        "guide_voice_scene3_desc": "Người dùng khiếm thị có thể nhận tất cả phản hồi của Bot qua giọng nói. Hỗ trợ đa ngôn ngữ, tốc độ có thể điều chỉnh, đảm bảo truyền đạt thông tin dễ tiếp cận.",
        "guide_voice_scene4_title": "🌍 Phát đa ngôn ngữ",
        "guide_voice_scene4_desc": "Hỗ trợ tiếng Trung phồn thể / Anh / Nhật / Hàn / Thái và nhiều ngôn ngữ khác. Phù hợp cho dịch vụ khách hàng đa ngôn ngữ — Bot tự động phát hiện ngôn ngữ và phản hồi bằng giọng nói tương ứng.",
        "guide_voice_flow": "Quy trình đầy đủ",
        "guide_voice_example": "Ví dụ mã nguồn",
        "guide_voice_example_desc": "OpenClaw Bot kích hoạt giọng nói khi trả lời người dùng:",
        "guide_voice_features": "Đặc điểm kỹ thuật",
        "guide_voice_feat1": "📱 <strong>Phát nền</strong>: Phát giọng nói ngay cả khi ứng dụng ở nền hoặc màn hình khóa (Foreground Service)",
        "guide_voice_feat2": "🔔 <strong>FCM dự phòng</strong>: Chuyển sang Firebase Cloud Messaging khi Socket.IO mất kết nối",
        "guide_voice_feat3": "🌐 <strong>Đa ngôn ngữ</strong>: Hỗ trợ tất cả ngôn ngữ mà engine Android TextToSpeech hỗ trợ",
        "guide_voice_feat4": "⚡ <strong>Độ trễ thấp</strong>: Từ khi Bot gọi đến khi người dùng nghe thường dưới 1 giây",
        "guide_voice_feat5": "🎛️ <strong>Tham số có thể điều chỉnh</strong>: Tốc độ và cao độ đều tùy chỉnh được (0.5x–2.0x)",
        "guide_voice_note": "💡 <strong>Lưu ý:</strong> TTS hiện chỉ hỗ trợ thiết bị Android. Hỗ trợ iOS đang được lên kế hoạch. Giới hạn văn bản 500 ký tự, vượt quá vui lòng chia nhỏ cuộc gọi.",
        "guide_voice_cta_title": "Dùng thử ngay",
        "guide_voice_cta_api": "Tài liệu API: <a href=\"https://eclawbot.com/api/skill-doc\" target=\"_blank\" rel=\"noopener\">API Skill Doc đầy đủ</a>",
        "guide_voice_cta_app": "Ứng dụng Android: <a href=\"https://play.google.com/store/apps/details?id=com.hank.clawlive\" target=\"_blank\" rel=\"noopener\">Tải từ Google Play</a>",

