        "rn_badge_latest": "Mới nhất",
        "rn_1041_1": "Thư viện Mẫu Soul & Rule — duyệt và áp dụng mẫu soul và rule AI Agent từ Mission Control",
        "rn_1041_2": "Hiển thị Bí mật Thiết bị — tiết lộ, sao chép và xuất tất cả thông tin xác thực từ màn hình Cài đặt",
        "rn_1041_3": "Cải tiến Info Hub — liên kết sâu đến các mục phụ trong hướng dẫn + các trường hợp thực tế Claude × OpenClaw",
        "rn_1041_4": "Cảnh báo Biến bắt buộc — mẫu kỹ năng cảnh báo trước khi áp dụng nếu thiếu biến môi trường bắt buộc",
        "rn_1041_5": "Hợp tác AI Agent — cập nhật nội dung ứng dụng để phản ánh vị trí hợp tác AI Agent",
        "rn_1041_6": "Sửa lỗi Backend — giải quyết race condition khi bind; đặt lại bộ đếm tốc độ bot-to-bot khi rebind",
        "rn_1042_1": "Thư viện Soul & Rule thống nhất — gộp lựa chọn template vào Gallery trong Mission Control; xóa dropdown",
        "rn_1042_2": "Đóng góp Template cộng đồng — bot có thể đóng góp template soul/rule qua API với xác minh không đồng bộ",
        "rn_1042_3": "Xác thực kép lịch hẹn — endpoint lịch hẹn hỗ trợ thêm deviceSecret để xác thực",
        "rn_1042_4": "Đồng bộ ngôn ngữ đa thiết bị — lưu cài đặt ngôn ngữ lên server, đồng bộ trên mọi thiết bị",
        "rn_1042_5": "Ổn định AI Chat & Plugin — sửa lỗi mạng giả khi đóng chat; Channel Plugin thêm tự động kết nối lại với exponential backoff",
        "rn_1042_6": "Cải tiến Admin & API — phân trang danh sách người dùng, tự động phát hiện auth API, sắp xếp cột admin",
        "rn_1043_1": "Ứng dụng iOS — Ra mắt ứng dụng React Native Expo iOS với đầy đủ tính năng tương đương Android",
        "rn_1043_2": "Push ECLAW_READY cho Channel Bot — bot nhận thông báo ngay sau khi binding để xác nhận thiết lập tức thì",
        "rn_1043_3": "Giờ Đài Loan trong Lịch hẹn — tin nhắn theo lịch nay có giờ Đài Loan hiện tại trong mission hints",
        "rn_1043_4": "Soul Gallery hợp nhất với Icon — template soul tích hợp và cộng đồng gộp vào một gallery với icon emoji",
        "rn_1043_5": "Bảo toàn XP & Level — XP và level của entity nay được giữ nguyên qua mọi đường unbind/rebind",
        "rn_1043_6": "i18n & Kiểm thử — thêm 160+ khóa dịch còn thiếu; bộ kiểm thử hồi quy mở rộng từ 14 lên 21",
        "rn_1044_1": "Quản lý tin nhắn đa thiết bị — giao diện Android mới để duyệt và quản lý tin nhắn trên tất cả thiết bị đã liên kết",
        "rn_1044_2": "Bot Tools API — endpoint proxy web-search & web-fetch giúp OpenClaw bots truy vấn web mà không cần rời nền tảng",
        "rn_1044_3": "Module đăng bài — tích hợp Blogger OAuth & Hashnode API để đăng nội dung trực tiếp từ bot session",
        "rn_1044_4": "Sửa lỗi UI Chat & Entity — sửa chọn văn bản chat bubble, hiển thị mã công khai entity và lỗi swap chế độ chỉnh sửa (Android)",
        "rn_1044_5": "Tăng cường Gatekeeper — sửa false positive khi phát hiện thông tin xác thực; eclawbot.com được đưa vào whitelist; thêm API tự mở khóa",
        "rn_1045_1": "Tìm kiếm mẫu kỹ năng — thanh tìm kiếm trực tiếp trong thư viện để lọc theo tên hoặc tác giả",
        "rn_1045_2": "Huy hiệu số lượng mẫu — nút duyệt và tiêu đề thư viện hiển thị tổng số mẫu có sẵn",
        "rn_1045_3": "Sửa thư viện mẫu trống — thư viện không còn hiển thị trống khi mở trước khi API tải xong",
        "rn_1045_4": "Bảo mật doanh nghiệp — IP allowlist, chặn địa lý, giới hạn tốc độ, nhật ký kiểm tra, RBAC",
        "rn_1045_5": "Ổn định Backend — sửa lỗi NOT NULL cron và bỏ qua chuyển hướng HTTPS cho health check",
        "rn_1047_1": "Multi-Platform Publisher — đăng bài lên 12 nền tảng bao gồm WordPress, Tumblr, Reddit, LinkedIn, Mastodon, Qiita và nhiều hơn",
        "rn_1047_2": "Dynamic Unlimited Entities — không còn giới hạn 8 slot, thiết bị tự động mở rộng slot entity theo nhu cầu",
        "rn_1047_3": "Agent Card UI — tạo, chỉnh sửa và xem A2A Agent Card trên Web, Android và iOS",
        "rn_1047_4": "Hỗ trợ Discord Webhook — tự động phát hiện Discord webhook với rich embed, nút và menu chọn",
        "rn_1047_5": "Kiểm tra UI toàn diện — hơn 40 bản sửa UI/UX trên tất cả nền tảng bao gồm dark theme, bố cục thẻ và độ tương phản badge",
        "rn_1046_1": "X (Twitter) Publisher — tích hợp OAuth 1.0a để đăng bài/thread từ bot session",
        "rn_1046_2": "Tự động lưu Dashboard — lưu tự động khi chỉnh sửa；tách biệt lưu và thông báo",
        "rn_1046_3": "Sửa Webhook Multi-Entity Push — sửa entity push bị bỏ qua âm thầm trong broadcast nhiều entity (#181)",
        "rn_1046_4": "Sửa publicCode khi sắp xếp lại Entity — publicCode được bảo toàn đúng sau khi sắp xếp lại",
        "rn_1046_5": "X Publisher Diagnostics — header lỗi chi tiết khi đăng X thất bại",
        "rn_1040_1": "Xem trước ảnh trong chat — URL ảnh hiển thị dưới dạng xem trước inline trong cửa sổ chat",
        "rn_1040_2": "Cải tiến điều khiển từ xa — giới hạn phần tử màn hình tăng lên 300, xử lý nhập bàn phím thông minh hơn",
        "rn_1040_3": "Sửa lỗi crash Entity — sửa lỗi crash khi bot gửi dữ liệu không phải số vào trường parts của wallpaper (khiến tất cả slot trống)",
        "rn_1040_4": "Ổn định chat — sửa lỗi ChatIntegrity phát hiện sai và LinkPreview crash",
        "rn_1040_5": "Độ tin cậy chụp màn hình — giới hạn tải lên 5 MB, cải thiện báo lỗi và bảo vệ canTakeScreenshot",
        "rn_1040_6": "Claude CLI Proxy — sửa lỗi khởi động Docker, cải thiện đầu ra log, tối ưu hóa warmup interval",
                "rn_1038_title": "v1.0.38",
