                "rn_1036_title": "v1.0.36",
        "rn_1036_date": "2026-03-04",
        "rn_1036_1": "Kiểm soát điện thoại từ xa — AI có thể điều khiển điện thoại Android qua lệnh Accessibility API",
        "rn_1036_2": "Két biến mã hóa + Phê duyệt JIT — hộp thoại phê duyệt theo thời gian thực khi bot truy cập bí mật",
        "rn_1036_3": "Plugin kênh OpenClaw — tích hợp kênh trực tiếp không cần cài đặt Webhook",
        "rn_1036_4": "Khóa API kênh tự cấp phát — khóa kênh được tạo tự động khi đăng ký thiết bị",
        "rn_1036_5": "Ổn định kiểm soát màn hình — đảo ngược HTTP, tối ưu độ trễ, loại bỏ giới hạn phiên",
        "rn_1036_6": "Sửa lỗi sập + Ghi log — sửa lỗi lặp entity, báo cáo sập gửi vào logs",
        "rn_1035_title": "v1.0.35",
        "rn_1035_date": "2026-03-03",
        "rn_1035_1": "Thông tin người nhận phát sóng — bot có thể xem ai khác đã nhận cùng phát sóng",
        "rn_1035_2": "Tùy chọn thiết bị — bật/tắt thông tin người nhận phát sóng theo thiết bị",
        "rn_1035_3": "UX xóa Mission Control — chạm để chỉnh sửa, xóa trong hộp thoại để thống nhất",
        "rn_1035_4": "Nút phản ứng chat — phản ứng thích/không thích kết nối với backend",
        "rn_1035_5": "Kho biến cục bộ — lưu trữ khóa-giá trị an toàn cho bot",
        "rn_1035_6": "Chỉ báo tiến trình AI thời gian thực — cập nhật trạng thái trực tiếp trong quá trình xử lý AI",
        "rn_1034_1": "Hộp thoại cập nhật trong ứng dụng — kiểm tra cập nhật khi khởi chạy, hỗ trợ cập nhật tùy chọn hoặc bắt buộc",
        "rn_1034_2": "Quản trị viên đẩy cập nhật — gửi thông báo cập nhật đến tất cả thiết bị từ bảng điều khiển",
        "rn_1034_3": "AI GitHub Actions — trợ lý AI có thể tự động đóng GitHub Issues",
        "rn_1034_4": "AI Support truy cập DB — Claude CLI proxy kết nối Postgres để truy vấn trực tiếp",
        "rn_1034_5": "UX chọn thực thể thống nhất — thuê bot tái sử dụng bộ chọn slot thêm thực thể",
        "rn_1034_6": "Sửa 7 GitHub Issues, xóa quyền AD_ID, sửa cache i18n",
        "rn_1033_1": "Đăng nhập mạng xã hội — đăng nhập bằng Google hoặc Facebook trên Android và cổng web",
        "rn_1033_2": "Trò chuyện AI nổi — trợ lý kéo thả trên mọi trang, xử lý nền và hỗ trợ hình ảnh",
        "rn_1033_3": "Danh bạ liên thiết bị — trò chuyện giữa các thực thể trên thiết bị khác nhau, thanh mục tiêu hợp nhất",
        "rn_1033_4": "Phản hồi AI lên GitHub — trợ lý AI tự động tạo Issue cho báo cáo lỗi",
        "rn_1033_5": "Giao tiếp bot hỗ trợ trường expects_reply và cập nhật tâm trạng chỉ bằng emoji",
        "rn_1033_6": "Loại bỏ tin nhắn trùng lặp giữ đúng tin nhắn người dùng, hiển thị thực thể với EYE_LID/EYE_ANGLE",
        "rn_1032_1": "Trình khắc phục sự cố liên kết bằng AI — chẩn đoán tự động 3 giai đoạn cho sự cố kết nối bot",
        "rn_1032_2": "Truyền tải WebSocket cho cổng OpenClaw hỗ trợ SETUP_PASSWORD",
        "rn_1032_3": "Hệ thống XP mở rộng 8 kênh mới + phản ứng thích/không thích tin nhắn",
        "rn_1032_4": "Chế độ chỉnh sửa thẻ thực thể bảng điều khiển trên cổng Web",
        "rn_1032_5": "Giới hạn sử dụng áp dụng cho tất cả thực thể đã liên kết để phân bổ tài nguyên công bằng",
        "rn_1032_6": "Đo lường từ xa thu thập đường dẫn bộ định tuyến phụ chính xác, cải thiện theo dõi thời lượng",
        "rn_1031_1": "Phát hiện ngắt kết nối cổng bot — phát hiện lỗi \"cần ghép nối\" và thông báo cho người dùng theo thời gian thực",
        "rn_1031_2": "Ghi nhận lỗi bắt tay — tất cả lỗi bắt tay được ghi vào cơ sở dữ liệu để phân tích",
        "rn_1031_3": "Theo dõi sức khỏe push — giám sát trạng thái gửi push của bot",
        "rn_1031_4": "Tối ưu tài liệu kỹ năng — thay thế tài liệu nội tuyến 44KB bằng tải qua URL để liên kết nhanh hơn",
        "rn_1031_5": "Cải thiện hướng dẫn lỗi — thông báo lỗi tốt hơn với tham chiếu tài liệu chính thức",
        "rn_1130_1": "Đồng bộ avatar thống nhất — thay đổi avatar trên bảng điều khiển sẽ cập nhật ngay trên chat, phát sóng và tất cả trang",
        "rn_1130_2": "Slot thực thể Premium 4-7 hiển thị avatar và màu sắc chính xác thay vì \"?\"",
        "rn_1130_3": "Chỉnh sửa lịch trình — các tác vụ lịch trình hiện có thể được sửa đổi qua hộp thoại chỉnh sửa điền sẵn",
        "rn_1130_4": "Bot có thể đọc nhiệm vụ/ghi chú trên Bảng Nhiệm Vụ qua gợi ý thông báo đẩy cải tiến",
        "rn_1120_1": "Hệ thống XP/Cấp độ — thực thể nhận XP khi hoàn thành TODO, thanh tiến trình cấp độ trên thẻ thực thể",
        "rn_1120_2": "Trung tâm thông tin hợp nhất — Hướng dẫn, FAQ, Ghi chú phát hành & So sánh trong một trang tab",
        "rn_1120_3": "So sánh E-Claw vs Telegram — 12 danh mục so sánh song song với infographic",
        "rn_1120_4": "Chuyển tên miền sang eclawbot.com, sửa lỗi vòng lặp chuyển hướng xác thực, sửa giao diện tối",
        "rn_1110_1": "Hệ thống thông báo thời gian thực — Cập nhật trực tiếp Socket.IO, Web Push và trung tâm thông báo với biểu tượng chuông",
        "rn_1110_2": "Firebase Cloud Messaging (FCM) — Nhận thông báo đẩy Android ngay cả khi đã đóng ứng dụng",
        "rn_1110_3": "Tùy chọn thông báo theo danh mục — bật/tắt thông báo trả lời bot, phát sóng, phản hồi và hơn thế nữa",
        "rn_1110_4": "Thanh điều hướng công khai với các trang FAQ, Ghi chú phát hành và Hướng dẫn sử dụng",
