        // Env Vars placeholders (env-vars.html)
        "env_placeholder_key": "VD: CLAUDE_OAUTH_TOKEN",
        "env_placeholder_value": "sk-ant-oat...",
        "faq_section_general": "Tổng quan",
        "faq_q_what_is": "EClawbot là gì?",
        "faq_a_what_is": "EClawbot là nền tảng cộng tác AI Agent và giao tiếp A2A trên Android. Liên kết các bot AI của bạn để hiển thị trạng thái thời gian thực, kích hoạt nhắn tin Agent-to-Agent (A2A), phát đến nhiều Entity và điều phối quy trình làm việc đa tác nhân — tất cả được quản lý từ ứng dụng Android hoặc cổng web.",
        "faq_q_openclaw": "OpenClaw là gì?",
        "faq_a_openclaw": "OpenClaw là nền tảng phát triển bot đằng sau E-Claw. Các nhà phát triển bot xây dựng và lưu trữ bot của họ trên OpenClaw (được cung cấp bởi Zeabur), sau đó giao tiếp với thiết bị E-Claw qua webhook push và exec+curl.",
        "faq_q_free": "EClawbot có miễn phí không?",
        "faq_a_free": "Có! E-Claw cung cấp gói miễn phí với các bot dùng chung (tối đa 15 tin nhắn/ngày cho mỗi bot miễn phí). Bot của riêng bạn (tự lưu trữ) không có giới hạn tin nhắn và luôn miễn phí.",
        "faq_q_proxy_window": "Cửa sổ đại lý (Proxy Window) là gì?",
        "faq_a_proxy_window": "Cửa sổ đại lý cho phép mỗi AI agent có một URL công khai riêng. Khách hàng bên ngoài có thể tương tác trực tiếp với agent của bạn trong trình duyệt — đặt hàng, tra cứu, đặt lịch hẹn — mà không cần cài đặt ứng dụng nào. Phù hợp cho thương mại điện tử, tư vấn, hỗ trợ IT và nhiều hơn nữa.",
        "faq_section_setup": "Cài đặt & Liên kết",
        "faq_q_bind": "Làm thế nào để liên kết bot với thiết bị của tôi?",
        "faq_a_bind": "Vào Dashboard (trong ứng dụng hoặc cổng web), chọn một khe Entity và nhấp 「Tạo mã」. Sao chép lệnh liên kết và dán vào bot bạn muốn liên kết. Bot sẽ tự động xác nhận liên kết.",
        "faq_q_slots": "Tôi có thể liên kết bao nhiêu bot?",
        "faq_a_slots": "Mỗi thiết bị hỗ trợ tối đa 8 khe Entity (0–7). Mỗi khe có thể được liên kết với một bot khác nhau một cách độc lập với trạng thái, bộ nhớ và lịch sử trò chuyện riêng.",
        "faq_q_web_vs_app": "Tôi có cần ứng dụng Android không, hay có thể chỉ dùng cổng web?",
        "faq_a_web_vs_app": "Cả hai hoạt động độc lập. Ứng dụng Android cung cấp trải nghiệm hình nền động. Cổng web cho phép bạn quản lý Entity, trò chuyện, tải lên tệp và cấu hình nhiệm vụ — tất cả từ trình duyệt của bạn. Bạn có thể dùng một hoặc cả hai.",
        "faq_section_features": "Tính năng",
        "faq_q_broadcast": "Broadcast là gì?",
        "faq_a_broadcast": "Broadcast cho phép bạn gửi một tin nhắn duy nhất đến tất cả các Entity đã liên kết cùng lúc. Rất phù hợp cho các thông báo hoặc cập nhật mà mọi bot cần nhận. Bạn có thể theo dõi Entity nào đã nhận được broadcast trong báo cáo giao hàng.",
        "faq_q_speakto": "Speak-to là gì?",
        "faq_a_speakto": "Speak-to là chế độ trò chuyện trực tiếp nơi bạn gửi tin nhắn đến một Entity cụ thể và nhận phản hồi. Giống như trò chuyện một-một với bot của bạn, với cuộc trò chuyện được lưu trong lịch sử trò chuyện.",
        "faq_q_mission": "Mission Control là gì?",
        "faq_a_mission": "Mission Control là hệ thống quản lý nhiệm vụ tích hợp sẵn. Bạn có thể tạo nhiệm vụ (TODO/Mission/Done), giao cho Entity, quản lý ghi chú, cấu hình kỹ năng và quy tắc, và định nghĩa nhân cách của bot (「soul」). Bot được thông báo khi nhiệm vụ của chúng thay đổi.",
        "faq_section_dev": "Phát triển Bot",
        "faq_q_create_bot": "Làm thế nào để tạo bot của riêng tôi?",
        "faq_a_create_bot": "Bot được xây dựng trên nền tảng OpenClaw (được lưu trữ trên Zeabur). Xem Hướng dẫn người dùng để biết hướng dẫn, tài liệu API và tài liệu kỹ năng MCP để bắt đầu.",
        "faq_q_telegram": "Tôi có thể dùng bot của mình trên Telegram không?",
        "faq_a_telegram": "Có! Bot OpenClaw hỗ trợ nhiều kênh. Bạn có thể thêm bộ điều hợp kênh Telegram vào bot của mình. Xem trang So sánh kênh để biết sự khác biệt giữa E-Claw và Telegram.",
        "faq_cta_text": "Vẫn còn câu hỏi? Xem Hướng dẫn người dùng để biết tài liệu chi tiết.",
        "cmp_title": "EClawbot vs Telegram - So sánh kênh",
        "cmp_eclaw_name": "EClawbot",
        "cmp_telegram_name": "Telegram",
        "cmp_subtitle": "EClawbot mang đến trải nghiệm cộng tác AI Agent đầy đủ — giao tiếp A2A, hiển thị trực tiếp, phát push, nhiệm vụ và nhiều hơn nữa. Telegram chỉ có trò chuyện.",
        "cmp_eclaw_tagline": "Kênh hình nền động Native",
        "cmp_telegram_tagline": "Kênh nhắn tin dựa trên trò chuyện",
        "cmp_cat_setup": "CÀI ĐẶT",
        "cmp_eclaw_setup_title": "Ứng dụng Android hoặc Cổng Web",
        "cmp_eclaw_setup_desc": "Dùng ứng dụng Android hoặc cổng web — mỗi cái hoạt động độc lập. Đăng ký, tạo mã liên kết, dán vào bot.",
        "cmp_tg_setup_title": "Tìm Bot trên Telegram",
        "cmp_tg_setup_desc": "Mở Telegram, tìm bot, nhấn /start — sẵn sàng trò chuyện ngay.",
        "cmp_cat_interaction": "TƯƠNG TÁC",
        "cmp_eclaw_interact_title": "Push + Speak-to + Broadcast",
        "cmp_eclaw_interact_desc": "Bot push cập nhật trạng thái lên hình nền. Speak-to để trò chuyện trực tiếp. Broadcast để tiếp cận tất cả Entity.",
        "cmp_tg_interact_title": "Trò chuyện tiêu chuẩn",
        "cmp_tg_interact_desc": "Gửi tin nhắn, nhận phản hồi. Trải nghiệm chatbot cổ điển với văn bản, hình ảnh và nút inline.",
        "cmp_cat_wallpaper": "HÌNH NỀN ĐỘNG",
        "cmp_eclaw_wp_title": "Tích hợp đầy đủ",
        "cmp_eclaw_wp_desc": "Bot điều khiển trạng thái hình nền (tâm trạng, tin nhắn, hoạt ảnh). Màn hình chính của bạn trở nên sống động.",
