        "guide_crossdevice_title": "Pesan Lintas Perangkat — Panduan Lengkap",
        "guide_crossdevice_meta": "Gerbang pertama untuk pesan masuk: penyaringan, pembatasan laju, dan kontrol akses dalam satu tempat",
        "guide_crossdevice_h2_what": "Apa itu Pesan Lintas Perangkat?",
        "guide_crossdevice_p_what": "Pesan Lintas Perangkat adalah gerbang yang mengontrol pesan eksternal masuk ke Bot Anda melalui Public Code. Ini bertindak sebagai garis pertahanan pertama sebelum pesan mencapai agent Anda, memungkinkan Anda mengontrol secara tepat siapa yang dapat mengirim pesan, konten apa yang lolos, dan seberapa sering setiap pengirim dapat mengirim pesan.",
        "guide_crossdevice_note_scenario": "💡 Konfigurasi: <strong>Dashboard → Pilih Entitas → Edit → ⚙ Cross-Device Msg</strong>. Bersama dengan Identity dan Agent Card, ketiga pengaturan ini mendefinisikan profil eksternal dan internal Bot Anda secara lengkap.",
        "guide_crossdevice_h2_how": "Cara Kerja",
        "guide_crossdevice_flow_client": "Pengguna Eksternal",
        "guide_crossdevice_flow_client_sub": "Jendela Proxy",
        "guide_crossdevice_flow_gate": "Gerbang",
        "guide_crossdevice_flow_gate_sub": "6 Pemeriksaan",
        "guide_crossdevice_flow_bot_sub": "Proses Pesan",
        "guide_crossdevice_p_how": "Pesan masuk melewati 6 pemeriksaan berurutan: Blokir Card Holder → Daftar hitam → Daftar putih → Kata terlarang → Jenis media → Batas laju. Jika ada pemeriksaan yang gagal, pesan ditolak dengan pesan penolakan kustom opsional.",
        "guide_crossdevice_h2_settings": "Referensi Pengaturan",
        "guide_crossdevice_th_setting": "Pengaturan",
        "guide_crossdevice_th_desc": "Deskripsi",
        "guide_crossdevice_set_preinject": "Instruksi Pre-inject",
        "guide_crossdevice_set_preinject_desc": "Teks yang otomatis ditambahkan sebelum pesan masuk sebelum mencapai Bot. Gunakan untuk konteks atau prompt peran. Maks 500 karakter.",
        "guide_crossdevice_set_forbidden": "Kata Terlarang",
        "guide_crossdevice_set_forbidden_desc": "Pesan yang mengandung kata kunci ini akan ditolak (tidak peka huruf besar/kecil). Pisahkan beberapa kata dengan koma.",
        "guide_crossdevice_set_ratelimit": "Batas Laju",
        "guide_crossdevice_set_ratelimit_desc": "Cooldown dalam detik per pengirim (0 = tanpa batas, maks 86400 = 1 hari). Mencegah pengiriman pesan berlebihan.",
        "guide_crossdevice_set_blacklist": "Daftar Hitam",
        "guide_crossdevice_set_blacklist_desc": "Public Code yang akan diblokir. Pesan dari sumber ini selalu ditolak.",
        "guide_crossdevice_set_whitelist_mode": "Mode Daftar Putih",
        "guide_crossdevice_set_whitelist_mode_desc": "Saat diaktifkan, hanya sumber dalam daftar putih yang dapat mengirim pesan. Semua sumber lain ditolak.",
        "guide_crossdevice_set_whitelist": "Daftar Putih",
        "guide_crossdevice_set_whitelist_desc": "Saat mode daftar putih aktif, hanya pesan dari Public Code ini yang diizinkan lolos.",
        "guide_crossdevice_set_reject": "Pesan Penolakan",
        "guide_crossdevice_set_reject_desc": "Pesan kustom yang dikirim kembali saat pesan ditolak (kosong = penolakan diam). Maks 200 karakter.",
        "guide_crossdevice_set_media": "Media yang Diizinkan",
        "guide_crossdevice_set_media_desc": "Pilih format pesan yang diizinkan: teks, foto, suara, video, file. Jenis yang tidak dicentang akan ditolak.",
        "guide_crossdevice_h2_gate": "Urutan Pemeriksaan Gerbang",
        "guide_crossdevice_gate_li1": "<strong>1. Blokir Card Holder</strong> — Sumber yang diblokir di Card Holder akan dibuang secara diam-diam",
        "guide_crossdevice_gate_li2": "<strong>2. Daftar Hitam</strong> — Dicocokkan dengan daftar hitam; ditolak dengan pesan kustom",
        "guide_crossdevice_gate_li3": "<strong>3. Daftar Putih</strong> — Jika mode daftar putih aktif, sumber yang tidak terdaftar ditolak",
        "guide_crossdevice_gate_li4": "<strong>4. Kata Terlarang</strong> — Pesan yang mengandung kata terlarang ditolak (tidak peka huruf besar/kecil)",
        "guide_crossdevice_gate_li5": "<strong>5. Jenis Media</strong> — Jenis media yang tidak ada dalam daftar izin ditolak",
        "guide_crossdevice_gate_li6": "<strong>6. Batas Laju</strong> — Pengirim yang melebihi periode cooldown menerima error 429",
        "guide_crossdevice_h2_howto": "Cara Mengonfigurasi",
        "guide_crossdevice_h3_web": "Metode Web Portal",
        "guide_crossdevice_web_li1": "Buka <strong>Dashboard</strong>",
        "guide_crossdevice_web_li2": "Pilih entitas dan klik <strong>Edit</strong>",
        "guide_crossdevice_web_li3": "Klik tombol <strong>⚙ Cross-Device Msg</strong> untuk membuka panel pengaturan",
        "guide_crossdevice_web_li4": "Isi kata terlarang, daftar hitam/putih, batas laju, dll.",
        "guide_crossdevice_web_li5": "Klik <strong>Save</strong> untuk menyimpan pengaturan",
        "guide_crossdevice_preview_preinject": "Pre-inject",
        "guide_crossdevice_preview_preinject_val": "Anda adalah asisten toko, balas dalam bahasa Indonesia",
        "guide_crossdevice_preview_forbidden": "Kata Terlarang",
        "guide_crossdevice_preview_ratelimit": "Batas Laju",
        "guide_crossdevice_preview_media": "Media",
        "guide_crossdevice_h3_api": "Metode API",
        "guide_crossdevice_api_auth": "Otentikasi: Header <code>x-device-secret</code>",
        "guide_crossdevice_h2_usecases": "Kasus Penggunaan",
        "guide_crossdevice_uc1_title": "🛡️ Anti-Pelecehan",
        "guide_crossdevice_uc1_desc": "Atur kata terlarang untuk menyaring konten tidak pantas, aktifkan batas laju untuk mencegah pengiriman pesan berlebihan, dan masukkan pengguna jahat ke daftar hitam secara permanen.",
        "guide_crossdevice_uc2_title": "🔒 Layanan Khusus VIP",
        "guide_crossdevice_uc2_desc": "Aktifkan mode daftar putih agar hanya Public Code klien tertentu yang dapat mengakses agent Anda, menciptakan saluran VIP eksklusif.",
        "guide_crossdevice_uc3_title": "📝 Preset Konteks",
        "guide_crossdevice_uc3_desc": "Gunakan Pre-inject untuk otomatis menambahkan prompt peran sebelum setiap pesan eksternal, misalnya 'Anda adalah penasihat perjalanan, balas dengan nada ramah.'",
        "guide_crossdevice_h2_tips": "Praktik Terbaik",
        "guide_crossdevice_tip_li1": "✅ <strong>Mulai longgar, perketat nanti</strong>: Mulai dengan pengaturan default dan tambahkan pembatasan secara bertahap sesuai kebutuhan",
        "guide_crossdevice_tip_li2": "✅ <strong>Gunakan Pre-inject dengan bijak</strong>: Berikan Bot Anda konteks peran lengkap dengan setiap pesan masuk",
        "guide_crossdevice_tip_li3": "✅ <strong>Atur pesan penolakan</strong>: Lebih ramah daripada penolakan diam — beri tahu pengguna yang diblokir alasannya",
        "guide_crossdevice_tip_li4": "✅ <strong>Padukan dengan Card Holder</strong>: Memblokir seseorang di Card Holder bertindak sebagai pemeriksaan gerbang pertama",
        "guide_crossdevice_warn": "⚠️ Batas laju dihitung di memori dan direset saat server restart. Daftar hitam, daftar putih, dan kata terlarang disimpan secara permanen di database.",
        "guide_crossdevice_note_back": "← <a href=\"#guide/usecase-proxy-window\">Kembali ke Panduan Jendela Proxy</a>",
        "guide_crossdevice_config_title": "Cross-Device Msg",

        // ── Voice TTS Guide ──
        "guide_nav_usecase_voice": "Percakapan Suara TTS",
        "guide_voice_title": "🔊 Percakapan Suara — Bot TTS Balasan Suara Real-Time",
        "guide_voice_subtitle": "Buat AI agent Anda \"berbicara\" — balasan suara langsung melalui speaker ponsel",
        "guide_voice_what": "Apa ini?",
        "guide_voice_what_desc": "<strong>TTS (Text-to-Speech) API</strong> EClawbot memungkinkan Bot memutar suara secara real-time melalui speaker perangkat Android. Suara tetap diputar meskipun aplikasi berjalan di latar belakang. Cocok untuk skenario yang membutuhkan interaksi suara — balasan suara layanan pelanggan, asisten suara, bantuan aksesibilitas, dll.",
        "guide_voice_how": "Cara Kerja",
        "guide_voice_how_desc": "Bot memanggil TTS API → Server meneruskan ke App → Engine Android TextToSpeech membacakan → Pengguna mendengar balasan suara",
        "guide_voice_api": "Penggunaan API",
