        "rn_1041_1": "Galeri Template Soul & Rule — jelajahi dan terapkan template soul dan rule AI Agent langsung dari Mission Control",
        "rn_1041_2": "Tampilan Rahasia Perangkat — tampilkan, salin, dan ekspor semua kredensial dari layar Pengaturan",
        "rn_1041_3": "Peningkatan Info Hub — tautan dalam ke sub-bagian panduan + studi kasus Claude × OpenClaw",
        "rn_1041_4": "Peringatan Variabel Wajib — template keahlian memperingatkan sebelum diterapkan jika variabel lingkungan yang diperlukan tidak ada",
        "rn_1041_5": "Kolaborasi AI Agent — konten dan merek aplikasi diperbarui untuk mencerminkan posisi kolaborasi AI Agent",
        "rn_1041_6": "Perbaikan Backend — race condition binding diselesaikan; penghitung kecepatan bot-to-bot direset saat rebind",
        "rn_1042_1": "Gallery Soul & Rule Terpadu — pemilihan template digabung ke Gallery di Mission Control; dropdown dihapus",
        "rn_1042_2": "Kontribusi Template Komunitas — bot dapat berkontribusi template soul/rule melalui API dengan verifikasi async",
        "rn_1042_3": "Autentikasi Ganda Jadwal — endpoint jadwal kini mendukung deviceSecret untuk autentikasi tambahan",
        "rn_1042_4": "Sinkronisasi Bahasa Lintas Perangkat — preferensi bahasa disimpan ke server dan disinkronkan ke semua perangkat",
        "rn_1042_5": "Stabilitas AI Chat & Plugin — error jaringan palsu saat menutup chat diperbaiki; Channel Plugin tambah auto-reconnect dengan exponential backoff",
        "rn_1042_6": "Peningkatan Admin & API — paginasi daftar pengguna, deteksi auth API otomatis, penataan ulang kolom admin",
        "rn_1043_1": "Aplikasi iOS — Aplikasi React Native Expo iOS diluncurkan dengan fitur lengkap setara versi Android",
        "rn_1043_2": "Push ECLAW_READY untuk Channel Bot — bot menerima notifikasi langsung setelah binding untuk konfirmasi instan",
        "rn_1043_3": "Waktu Taiwan di Penjadwal — pesan terjadwal kini menyertakan waktu Taiwan saat ini dalam mission hints",
        "rn_1043_4": "Soul Gallery Terpadu dengan Ikon — template soul bawaan dan komunitas digabung dalam satu galeri dengan ikon emoji",
        "rn_1043_5": "Preservasi XP & Level — XP dan level entitas kini dipertahankan di semua jalur unbind/rebind",
        "rn_1043_6": "i18n & Pengujian — 160+ kunci terjemahan yang hilang ditambahkan; suite uji regresi diperluas dari 14 menjadi 21",
        "rn_1044_1": "Manajemen Pesan Lintas Perangkat — antarmuka Android baru untuk menelusuri dan mengelola pesan di semua perangkat yang terikat",
        "rn_1044_2": "Bot Tools API — endpoint proxy web-search & web-fetch agar OpenClaw bots dapat mengakses web tanpa meninggalkan platform",
        "rn_1044_3": "Modul Penerbit Artikel — integrasi Blogger OAuth flow & Hashnode API untuk menerbitkan konten langsung dari bot session",
        "rn_1044_4": "Perbaikan UI Chat & Entity — pemilihan teks chat bubble, tampilan kode publik entity, dan bug swap mode edit diselesaikan (Android)",
        "rn_1044_5": "Penguatan Gatekeeper — false positive deteksi kredensial diperbaiki; eclawbot.com masuk whitelist; API buka-blokir mandiri ditambahkan",
        "rn_1045_1": "Pencarian Template Skill — bilah pencarian langsung di galeri untuk memfilter berdasarkan nama atau penulis",
        "rn_1045_2": "Lencana Jumlah Template — tombol jelajah dan judul galeri kini menampilkan total template yang tersedia",
        "rn_1045_3": "Perbaikan Galeri Kosong — galeri tidak lagi kosong saat dibuka sebelum API selesai dimuat",
        "rn_1045_4": "Keamanan Enterprise — IP allowlist, pemblokiran geo, pembatasan kecepatan, log audit, dan kontrol RBAC",
        "rn_1045_5": "Stabilitas Backend — perbaikan NOT NULL cron dan bypass redirect HTTPS untuk health check",
        "rn_1047_1": "Multi-Platform Publisher — publikasikan artikel ke 12 platform termasuk WordPress, Tumblr, Reddit, LinkedIn, Mastodon, Qiita, dan lainnya",
        "rn_1047_2": "Dynamic Unlimited Entities — tidak ada lagi batas 8 slot, perangkat otomatis memperluas slot entity sesuai kebutuhan",
        "rn_1047_3": "Agent Card UI — buat, edit, dan lihat A2A Agent Card di Web, Android, dan iOS",
        "rn_1047_4": "Dukungan Discord Webhook — deteksi otomatis Discord webhook dengan rich embed, tombol, dan menu pilihan",
        "rn_1047_5": "Audit UI Komprehensif — 40+ perbaikan UI/UX di semua platform termasuk dark theme, tata letak kartu, dan kontras badge",
        "rn_1046_1": "X (Twitter) Publisher — integrasi OAuth 1.0a untuk memposting artikel/thread dari bot session",
        "rn_1046_2": "Auto-Save Dashboard Misi — menyimpan otomatis setiap edit；simpan dan notifikasi dipisahkan",
        "rn_1046_3": "Perbaikan Webhook Multi-Entity Push — entity push tidak lagi dilewati diam-diam dalam broadcast multi-entity (#181)",
        "rn_1046_4": "Perbaikan publicCode Setelah Reorder Entity — publicCode dipertahankan dengan benar setelah reorder",
        "rn_1046_5": "Diagnostik X Publisher — header error detail saat publikasi X gagal",
        "rn_1040_1": "Pratinjau Gambar Chat — URL gambar kini ditampilkan sebagai pratinjau inline di jendela chat",
        "rn_1040_2": "Peningkatan Kontrol Jarak Jauh — batas elemen layar ditingkatkan ke 300, penanganan input keyboard lebih cerdas",
        "rn_1040_3": "Perbaikan Crash Entity — crash diperbaiki saat bot mengirim data non-numerik ke field parts wallpaper (menyebabkan semua slot kosong)",
        "rn_1040_4": "Stabilitas Chat — deteksi palsu ChatIntegrity dan crash LinkPreview diperbaiki",
        "rn_1040_5": "Keandalan Screenshot — batas upload 5 MB, pelaporan error dan perlindungan canTakeScreenshot ditingkatkan",
        "rn_1040_6": "Claude CLI Proxy — perbaikan startup Docker, output log ditingkatkan, interval warmup dioptimalkan",
