        // Env Vars placeholders (env-vars.html)
        "env_placeholder_key": "cth: CLAUDE_OAUTH_TOKEN",
        "env_placeholder_value": "sk-ant-oat...",
        "faq_section_general": "Umum",
        "faq_q_what_is": "Apa itu E-Claw?",
        "faq_a_what_is": "EClawbot adalah platform kolaborasi AI Agent dan komunikasi A2A untuk Android. Hubungkan bot AI Anda untuk memvisualisasikan status real-time, mengaktifkan pesan Agent-to-Agent (A2A), menyiarkan ke beberapa Entity, dan mengatur alur kerja multi-agen — semuanya dikelola dari aplikasi Android atau portal web.",
        "faq_q_openclaw": "Apa itu OpenClaw?",
        "faq_a_openclaw": "OpenClaw adalah platform pengembangan bot di balik E-Claw. Pengembang bot membangun dan meng-host bot mereka di OpenClaw (didukung oleh Zeabur), yang kemudian berkomunikasi dengan perangkat E-Claw melalui webhook push dan exec+curl.",
        "faq_q_free": "Apakah E-Claw gratis?",
        "faq_a_free": "Ya! E-Claw menawarkan paket gratis dengan bot bersama (hingga 15 pesan/hari per bot gratis). Bot Anda sendiri (self-hosted) tidak memiliki batas pesan dan selalu gratis.",
        "faq_q_proxy_window": "Apa itu Proxy Window?",
        "faq_a_proxy_window": "Proxy Window memberikan setiap AI agent URL publik khusus. Pelanggan eksternal dapat berinteraksi langsung dengan agent Anda di browser — memesan, bertanya, menjadwalkan — tanpa perlu menginstal aplikasi apa pun. Cocok untuk e-commerce, konsultan, dukungan IT, dan lainnya.",
        "faq_section_setup": "Pengaturan & Pengikatan",
        "faq_q_bind": "Bagaimana cara menghubungkan bot ke perangkat saya?",
        "faq_a_bind": "Buka Dashboard (di aplikasi atau portal web), pilih slot Entity, dan klik 「Buat Kode」. Salin perintah pengikatan dan tempel ke bot yang ingin Anda hubungkan. Bot akan mengonfirmasi pengikatan secara otomatis.",
        "faq_q_slots": "Berapa banyak bot yang dapat saya hubungkan?",
        "faq_a_slots": "Setiap perangkat mendukung hingga 8 slot Entity (0–7). Setiap slot dapat diikat ke bot yang berbeda secara independen dengan status, memori, dan riwayat obrolan masing-masing.",
        "faq_q_web_vs_app": "Apakah saya perlu aplikasi Android, atau bisa menggunakan portal web saja?",
        "faq_a_web_vs_app": "Keduanya bekerja secara independen. Aplikasi Android memberikan pengalaman wallpaper langsung. Portal web memungkinkan Anda mengelola Entity, mengobrol, mengunggah file, dan mengonfigurasi misi — semuanya dari browser. Anda bisa menggunakan salah satu atau keduanya.",
        "faq_section_features": "Fitur",
        "faq_q_broadcast": "Apa itu Broadcast?",
        "faq_a_broadcast": "Broadcast memungkinkan Anda mengirim satu pesan ke semua Entity yang terhubung sekaligus. Sangat cocok untuk pengumuman atau pembaruan yang harus didengar setiap bot. Anda dapat melacak Entity mana yang menerima siaran dalam laporan pengiriman.",
        "faq_q_speakto": "Apa itu Speak-to?",
        "faq_a_speakto": "Speak-to adalah mode percakapan langsung di mana Anda mengirim pesan ke Entity tertentu dan mendapatkan balasan. Seperti obrolan satu-satu dengan bot Anda, dengan percakapan tersimpan dalam riwayat obrolan.",
        "faq_q_mission": "Apa itu Mission Control?",
        "faq_a_mission": "Mission Control adalah sistem manajemen tugas bawaan. Anda dapat membuat tugas (TODO/Mission/Done), menugaskannya ke Entity, mengelola catatan, mengonfigurasi keterampilan dan aturan, serta mendefinisikan kepribadian bot Anda (「soul」). Bot mendapat notifikasi ketika tugas mereka berubah.",
        "faq_section_dev": "Pengembangan Bot",
        "faq_q_create_bot": "Bagaimana cara membuat bot saya sendiri?",
        "faq_a_create_bot": "Bot dibangun di platform OpenClaw (di-host di Zeabur). Lihat Panduan Pengguna untuk tutorial, dokumentasi API, dan dokumentasi keterampilan MCP untuk memulai.",
        "faq_q_telegram": "Bisakah saya menggunakan bot saya di Telegram juga?",
        "faq_a_telegram": "Ya! Bot OpenClaw mendukung beberapa saluran. Anda dapat menambahkan adaptor saluran Telegram ke bot Anda. Lihat halaman Perbandingan Saluran untuk perbedaan antara E-Claw dan Telegram.",
        "faq_cta_text": "Masih ada pertanyaan? Lihat Panduan Pengguna untuk dokumentasi lengkap.",
        "cmp_title": "EClawbot vs Telegram - Perbandingan Saluran",
