// Portal version for sync tracking
const PORTAL_VERSION = '1.2.0';

class I18n {
    constructor() {
        const saved = localStorage.getItem('eclaw-language');
        if (saved && TRANSLATIONS[saved]) {
            this.lang = saved;
        } else {
            // Auto-detect from browser/device language
            const browserLang = (navigator.language || navigator.userLanguage || 'en').toLowerCase();
            const langMap = [
                [['zh-cn', 'zh-hans', 'zh-sg'], 'zh-CN'],
                [['zh'], 'zh'],
                [['ja'], 'ja'],
                [['ko'], 'ko'],
                [['th'], 'th'],
                [['vi'], 'vi'],
                [['id', 'in'], 'id'],
                [['es'], 'es'],
                [['fr'], 'fr'],
                [['de'], 'de'],
                [['pt'], 'pt'],
                [['it'], 'it'],
                [['ru'], 'ru'],
                [['tr'], 'tr'],
                [['ms', 'my'], 'ms'],
                [['hi'], 'hi'],
                [['ar'], 'ar'],
                [['nl'], 'nl'],
                [['pl'], 'pl'],
            ];
            let detected = 'en';
            for (const [prefixes, lang] of langMap) {
                if (prefixes.some(p => browserLang.startsWith(p)) && TRANSLATIONS[lang]) {
                    detected = lang;
                    break;
                }
            }
            this.lang = detected;
        }
        this.observers = [];
    }

    setLanguage(lang) {
        if (!TRANSLATIONS[lang]) return;
        this.lang = lang;
        localStorage.setItem('eclaw-language', lang);
        this.apply();
        this.observers.forEach(cb => cb(lang));
    }

    t(key, params = {}) {
        const dict = TRANSLATIONS[this.lang] || TRANSLATIONS['en'];
        let str = dict[key] || TRANSLATIONS['en'][key] || key;

        // Simple parameter replacement {name}
        Object.keys(params).forEach(k => {
            str = str.replace(new RegExp(`\\{${k}\\}`, 'g'), params[k]);
        });
        return str;
    }

    apply() {
        document.querySelectorAll('[data-i18n]').forEach(el => {
            const key = el.getAttribute('data-i18n');
            if (key) {
                const translated = this.t(key);
                // Skip if translation returns the key itself (no translation found)
                // This preserves the original HTML content as fallback
                if (translated === key) return;
                if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') {
                    if (el.hasAttribute('placeholder')) {
                        el.placeholder = translated;
                    }
                } else {
                    el.innerHTML = translated;
                }
            }
        });

        // Translate placeholder attributes
        document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
            const key = el.getAttribute('data-i18n-placeholder');
            if (key) {
                el.placeholder = this.t(key);
            }
        });

        // Translate title attributes
        document.querySelectorAll('[data-i18n-title]').forEach(el => {
            const key = el.getAttribute('data-i18n-title');
            if (key) {
                const translated = this.t(key);
                if (translated !== key) {
                    el.title = translated;
                    el.setAttribute('aria-label', translated);
                }
            }
        });

        // Update html lang attribute
        const langMap = { 'zh': 'zh-TW', 'zh-CN': 'zh-CN', 'ja': 'ja', 'ko': 'ko', 'th': 'th', 'vi': 'vi', 'id': 'id', 'ms': 'ms' };
        document.documentElement.lang = langMap[this.lang] || 'en';
    }

    onLanguageChange(cb) {
        this.observers.push(cb);
    }
}

// Global instance
const i18n = new I18n();

// Auto-apply on load
document.addEventListener('DOMContentLoaded', () => {
    i18n.apply();
});
